INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-23e15ae5-moex-00310', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '冉求曰：「非不說子之道，力不足也。」子曰：「力不足者，中道而廢， 今女畫。」（《論語．雍也》）根據上文，孔子認為冉求的學習態度是：', '["力不從心", "打退堂鼓", "畫地自限", "得過且過"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00311', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「 ，終其一生，以醫術救治人的肉體，以文學剖析臺灣被殖民的諸多 面向，其文學作品採『寫實主義』的手法，啟蒙、左翼、抵抗性、反殖民、 本土－－皆可從 的文學中窺見其身影，且洋溢著民族情感與人道主 義，被譽為『臺灣文學之父』。」上文兩處空格，皆應填入何人？', '["楊逵", "賴和", "蔣渭水", "連雅堂"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00312', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '荀子說：「造父者，天下之善御者也，無輿馬則無所見其能；羿者，天下 之善射者也，無弓矢則無所見其巧。」這段話的意義，與下列敘述何者最 相近？', '["獨樂樂，不若眾樂樂", "無米之炊，巧婦難為", "人無遠慮，必有近憂", "人各有志，出處異趣"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00313', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '魯迅《中國小說史略》：「描寫委曲，敘次井然，用傳奇法，而以志怪， 變幻之狀，如在目前。……使花妖狐魅，皆具人情，和易可親，忘為異類。」 此段文字應是評論那一部作品？', '["山海經", "搜神記", "唐人傳奇", "聊齋志異"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00314', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '下列選項中的敘述，何者錯誤？', '["「三教九流」中的三教是指儒教、佛教、道教", "「三姑六婆」是指親屬之間的正常稱謂，後用以比喻人多嘴雜", "「六甲」相傳是上天創造萬物的日子，故稱女子懷孕為「身懷六甲」", "「三頭六臂」是指某一種天神的長相，後用以比喻人神通廣大，能力很強"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00315', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '下列選項與孔子「學而不厭」之精神，最接近的是：', '["學而不思則罔，思而不學則殆", "發憤忘食，樂以忘憂，不知老之將至云爾", "吾嘗終日不食，終夜不寢，以思；無益，不如學也", "不憤不啟，不悱不發，舉一隅不以三隅反，則不復也"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00316', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '世皆稱孟嘗君能得士，士以故歸之，而卒賴其力以脫於虎豹之秦。嗟乎！ 孟嘗君特雞鳴狗盜之雄耳，豈足以言得士！不然，擅齊之強，得一士焉， 宜可以南面而制秦，尚何取雞鳴狗盜之力哉？夫雞鳴狗盜之出其門，此士 之所以不至也。（王安石〈讀孟嘗君傳〉）本文意旨為何？', '["剖析孟嘗君能得士的原因", "反駁孟嘗君能得士的說法", "讚賞孟嘗君能得士的手段", "批判孟嘗君能得士的局勢"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00317', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '承上題，依據上文，下列形容孟嘗君與其所得之士的關係，何者較為恰當？', '["物以類聚", "相得益彰", "各懷鬼胎", "陽奉陰違"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00318', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '海之魚，有烏賊其名者。呴水，而水鳥戲於岸間。懼物之窺己也，則呴水 以蔽物。海鳥疑而視之，知其魚也而攫之。嗚呼！徒知自蔽以求全，不知 滅迹以杜疑，為識者之所窺，哀哉！（蘇軾〈二魚說〉）依據文中敘述， 烏賊呴水之目的為何？', '["捕捉食物", "炫耀技能", "遊戲自娛", "自我保護"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00319', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '承上題，下列選項中的成語，何者最適合形容文中之烏賊？', '["掩耳盜鈴", "欲蓋彌彰", "自欺欺人", "束手就擒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
